    &#34;datasets&#34;: [
      { &#34;name&#34;: &#34;访问量&#34;, &#34;type&#34;: &#34;line&#34;, &#34;values&#34;: [12, 18, 9, 22] }
    ]
  },
  &#34;type&#34;: &#34;axis-mixed&#34;,
  &#34;height&#34;: 240,
  &#34;colors&#34;: [&#34;#7cd6fd&#34;]
});
                window.addEventListener(&#39;pjax:send&#39;, function() {
                    chart4edcad96b31345c393da132fce181599.destroy()
                });
            &lt;/script&gt;&lt;hr /&gt;
&lt;h2 id=&#34;十一-提示框container&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#十一-提示框container&#34;&gt;#&lt;/a&gt; 十一、提示框（container）&lt;/h2&gt;
&lt;div class=&#34;note default&#34;&gt;
&lt;p&gt;默认提示框&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note primary&#34;&gt;
&lt;p&gt;primary 强调&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;info 说明&lt;/p&gt;
&lt;/div&gt;
